/**
 * /llms.txt — index file per https://llmstxt.org/.
 *
 * Short, link-heavy summary of the KBVE site so language models can navigate
 * without crawling JS-rendered pages. Pulls links + titles from the docs
 * collection at build time so additions show up automatically.
 *
 * The OpenAPI section is now driven by the on-disk spec at
 * `packages/data/openapi/openapi.json` (generated by `axum-kbve --emit-openapi`).
 * No more curated `API_ENDPOINTS` list to keep in sync — adding a
 * `#[utoipa::path]` annotation on the Rust side and regenerating the spec
 * shows up here automatically.
 *
 * Companion file /llms-full.txt holds the full doc corpus.
 */
import { getCollection } from 'astro:content';
// Import the generated spec directly. Vite resolves the JSON at build time;
// the consumer is fully static. If openapi.json is empty / missing, the
// build fails fast with a clear error rather than emitting a half-broken
// llms.txt.
import openapiSpec from '../../../../../packages/data/openapi/openapi.json';

const SITE = 'https://kbve.com';

interface DocSummary {
	slug: string;
	title: string;
	description: string;
	category: string;
}

/** Collect doc entries grouped by top-level category. */
async function collectDocsByCategory(): Promise<Map<string, DocSummary[]>> {
	const allDocs = await getCollection('docs');
	const byCategory = new Map<string, DocSummary[]>();

	for (const entry of allDocs) {
		const data = entry.data as Record<string, unknown>;
		const title = typeof data.title === 'string' ? data.title : '';
		if (!title) continue;

		const description =
			typeof data.description === 'string' ? data.description.trim() : '';

		const slug = entry.id;
		const segments = slug.split('/');
		const category = segments[0] ?? '';
		if (!category || category === 'index.mdx') continue;

		const list = byCategory.get(category) ?? [];
		list.push({ slug, title, description, category });
		byCategory.set(category, list);
	}

	for (const list of byCategory.values()) {
		list.sort((a, b) => a.title.localeCompare(b.title));
	}

	return byCategory;
}

interface ApiEndpoint {
	method: string;
	path: string;
	summary: string;
	tag: string;
}

/** Iterate the OpenAPI spec and flatten paths × methods into a list of
 * endpoint summaries grouped by tag. The summary falls back to the
 * description if no operation summary is set, then to the operationId,
 * then a generic fallback. */
function collectApiEndpoints(): Map<string, ApiEndpoint[]> {
	const byTag = new Map<string, ApiEndpoint[]>();
	const HTTP_METHODS = [
		'get',
		'post',
		'put',
		'patch',
		'delete',
		'head',
		'options',
		'trace',
	] as const;

	const paths =
		(openapiSpec as { paths?: Record<string, unknown> }).paths ?? {};
	for (const [path, pathItemRaw] of Object.entries(paths)) {
		const pathItem = pathItemRaw as Record<string, unknown>;
		for (const method of HTTP_METHODS) {
			const op = pathItem[method] as
				| {
						summary?: string;
						description?: string;
						operationId?: string;
						tags?: string[];
				  }
				| undefined;
			if (!op) continue;

			const tag = op.tags?.[0] ?? 'untagged';
			const summary =
				op.summary?.trim() ||
				op.description?.split('\n')[0]?.trim() ||
				op.operationId ||
				'(no summary)';

			const list = byTag.get(tag) ?? [];
			list.push({
				method: method.toUpperCase(),
				path,
				summary,
				tag,
			});
			byTag.set(tag, list);
		}
	}

	for (const list of byTag.values()) {
		list.sort(
			(a, b) =>
				a.path.localeCompare(b.path) ||
				a.method.localeCompare(b.method),
		);
	}

	return byTag;
}

/** Top-level categories surfaced in the docs section. Kept short by design;
 * the long tail lives in /llms-full.txt. */
const FEATURED_CATEGORIES = [
	'project',
	'application',
	'gdd',
	'journal',
	'company',
];

const CATEGORY_TITLES: Record<string, string> = {
	project: 'Projects',
	application: 'Application Stack',
	gdd: 'Game Design Documents',
	journal: 'Engineering Journal',
	company: 'Company',
};

const PER_CATEGORY_LIMIT = 30;

/** Tag display order for the API section. Tags not listed here fall through
 * to alphabetical order at the end. */
const TAG_ORDER = [
	'system',
	'auth',
	'profile',
	'forum',
	'osrs',
	'mc',
	'telemetry',
];

const TAG_TITLES: Record<string, string> = {
	system: 'System',
	auth: 'Authentication',
	profile: 'Profile',
	forum: 'Forum',
	osrs: 'OSRS (Old School RuneScape)',
	mc: 'Minecraft',
	telemetry: 'Telemetry',
};

export const GET = async () => {
	const byCategory = await collectDocsByCategory();
	const byTag = collectApiEndpoints();
	const lines: string[] = [];

	const info = (
		openapiSpec as { info?: { title?: string; description?: string } }
	).info;
	const apiTitle = info?.title ?? 'KBVE API';

	lines.push('# KBVE');
	lines.push('');
	lines.push(
		'> Open-source software collective and game studio. Builds web infrastructure, Minecraft mods, multiplayer games, and developer tooling. Operates a Kubernetes-managed stack on Talos backing kbve.com.',
	);
	lines.push('');
	lines.push(
		'KBVE runs the kbve.com website, a Discord community, multiple game projects (RareIcon, ChuckRPG, RentEarth, KBVE-MC), and the axum-kbve API. Source lives at https://github.com/KBVE/kbve.',
	);
	lines.push('');

	// Docs by category, top section first
	for (const cat of FEATURED_CATEGORIES) {
		const entries = byCategory.get(cat);
		if (!entries || entries.length === 0) continue;
		const heading = CATEGORY_TITLES[cat] ?? cat;
		lines.push(`## ${heading}`);
		lines.push('');
		const slice = entries.slice(0, PER_CATEGORY_LIMIT);
		for (const e of slice) {
			const url = `${SITE}/${e.slug}/`;
			const desc = e.description ? ` — ${e.description}` : '';
			lines.push(`- [${e.title}](${url})${desc}`);
		}
		if (entries.length > slice.length) {
			lines.push(
				`- ${entries.length - slice.length} more entries in this section — see [/llms-full.txt](${SITE}/llms-full.txt) for the full corpus`,
			);
		}
		lines.push('');
	}

	// API surface — generated from packages/data/openapi/openapi.json
	lines.push(`## ${apiTitle}`);
	lines.push('');
	lines.push(
		`- [Interactive API reference](${SITE}/dashboard/api/) — Scalar-rendered live spec`,
	);
	lines.push(
		`- [OpenAPI 3.1 spec](${SITE}/api/openapi.json) — machine-readable JSON, generated by utoipa`,
	);
	lines.push('');

	// Walk tags in priority order, then any remaining tags alphabetically.
	const seenTags = new Set<string>();
	const orderedTags = [
		...TAG_ORDER.filter((t) => byTag.has(t)),
		...[...byTag.keys()].filter((t) => !TAG_ORDER.includes(t)).sort(),
	];

	for (const tag of orderedTags) {
		if (seenTags.has(tag)) continue;
		seenTags.add(tag);
		const eps = byTag.get(tag);
		if (!eps || eps.length === 0) continue;

		const heading =
			TAG_TITLES[tag] ?? tag.charAt(0).toUpperCase() + tag.slice(1);
		lines.push(`### ${heading}`);
		lines.push('');
		for (const ep of eps) {
			lines.push(`- \`${ep.method} ${ep.path}\` — ${ep.summary}`);
		}
		lines.push('');
	}

	// Optional / external
	lines.push('## Optional');
	lines.push('');
	lines.push(`- [GitHub repository](https://github.com/KBVE/kbve)`);
	lines.push(`- [Discord community](${SITE}/discord/)`);
	lines.push(`- [llms-full.txt](${SITE}/llms-full.txt) — full doc corpus`);
	lines.push('');

	const body = lines.join('\n');
	return new Response(body, {
		headers: {
			'Content-Type': 'text/plain; charset=utf-8',
			'Cache-Control': 'public, max-age=3600',
		},
	});
};
